static inline float N99P_ftube(int t, float v){
  float x=(v-N99P_VMIN)*((N99P_N-1)/(N99P_VMAX-N99P_VMIN));
  if(x<=0)x=0; if(x>=N99P_N-1)x=N99P_N-1.001f;
  int i=(int)x; float fr=x-i; const float*T=(t?N99P_FT1:N99P_FT0);
  return T[i]+fr*(T[i+1]-T[i]);
}
static inline float N99P_ranode(int t, float v){
  float x=(v-N99P_VMIN)*((N99P_N-1)/(N99P_VMAX-N99P_VMIN));
  if(x<=0)x=0; if(x>=N99P_N-1)x=N99P_N-1.001f;
  int i=(int)x; float fr=x-i; const float*T=(t?N99P_RA1:N99P_RA0);
  return T[i]+fr*(T[i+1]-T[i]);
}
